-- 2026-06-25: shoulder_instability_conservative — фазы «Путь» + структурированные критерии перехода.
-- Протокол: консервативная (безоперационная) реабилитация при нестабильности плечевого сустава
-- после вывиха (Conservative rehab for shoulder instability after dislocation).
--
-- Источник: PROTOCOLS/shoulder досье + proto_shoulder_instability_conservative.json
-- (объект suggested_program_type_code='shoulder_instability_conservative', anchor time_and_criterion).
-- Полностью КОНСЕРВАТИВНЫЙ протокол, единый program_type, БЕЗ отдельной хирургической ветки
-- (хирургия идёт по другим плечевым протоколам). 4 фазы (1–4), БЕЗ фазы 0/prehab — источник прямо:
-- «Фазы 0 / прехаба нет — она зарезервирована для послеоперационных протоколов». Старт с фазы 1.
--
-- Защитная ось: бережём заживающий капсульно-связочный аппарат (повреждение Банкарта) и не пускаем
-- сустав в провокационные диапазоны. Направление нестабильности — это curator-note внутри фаз
-- (НЕ отдельный program_type): передняя — запрет «отведение + поворот наружу» и переразгибания;
-- задняя — запрет «сгибание + приведение + поворот внутрь», иммобилизация в нейтральной ротации.
-- Возврат к спорту — по критериям, не по календарю («стабильность важнее скорости»).
--
-- Контент в ПАЦИЕНТСКОМ регистре (без клинич. жаргона PROM/AROM/ER/IR/MMT/apprehension/90-90/
-- SIRSI/Bankart/Hill-Sachs/Stanmore — раскрыт словами: «пассивный поворот руки наружу»,
-- «положение опасения = отведение + поворот наружу», «сила по мануальному тесту» и т.п.).
-- Vadim калибрует через AdminContent после деплоя.
--
-- criteria_next (free-text на rehab_phases) дублирует метки критериев → пациент видит их СРАЗУ
-- в «Пути». Структурированная phase_transition_criteria — для будущей авто-проверки (слот D2).
-- Фаза 4 (возврат к спорту) — конечная, но НЕСЁТ критерии готовности (извлечён явный блок
-- «Возврат к спорту/работе»), поэтому критерии включены.
--
-- Классификация критериев (ТЗ §2.3): measurement = боль ВАШ ТОЛЬКО (measurement_type='vas_score',
-- source='pain', как в ACL-seed 20260518). В этом протоколе числовых порогов по боли НЕТ — боль
-- описана качественно (сон без пробуждений) → идёт self_report; measurement-критериев нет вовсе
-- (faithful источнику). Числа по объёму движений / силе / сроку иммобилизации (градусы, баллы, %,
-- недели) система НЕ хранит → 'instructor_check' с порогом в ТЕКСТЕ label (куратор вводит очно).
-- Качественное да/нет от пациента → 'self_report'.
--
-- Идемпотентна: ON CONFLICT DO NOTHING для обеих таблиц (AdminContent = источник истины после
-- деплоя; ручная калибровка не затирается). Прогон тест-цикла createdb→schema→migrations×2 → ок.
-- НЕ трогает acl/knee/другие program_type (разные program_type/phase_id).

BEGIN;

-- =====================================================
-- 1. Фазы shoulder_instability_conservative (контент «Путь»)
-- =====================================================
INSERT INTO rehab_phases (program_type, phase_number, title, subtitle, duration_weeks, description, goals, restrictions, criteria_next, icon, color, color_bg, teaser, allowed, pain, daily, red_flags, faq)
VALUES
(
    'shoulder_instability_conservative', 1,
    'Защита и заживление',
    'Первые 0–3 (до 4) недели',
    '0-3',
    'Стартовый и самый осторожный этап. После вывиха капсула и связки только начинают заживать, поэтому плечо нужно защитить и держать в безопасном диапазоне. Рука пока в косыночной повязке; активно поднимать её и заводить в провокационные положения нельзя. Задача — унять боль, сохранить подвижность локтя и кисти и не дать мышцам ослабнуть за счёт лёгких напряжений без движения.',
    '["Дать зажить капсуле и связкам (месту повреждения)","Снизить боль и воспаление","Не дать мышцам ослабнуть с помощью напряжений без движения (изометрия)","Сохранить свободные движения локтя, запястья и кисти"]',
    '["При передней нестабильности: строго избегать «положения опасения» — сочетания отведения руки в сторону и поворота наружу; не переразгибать плечо назад и не заводить руку за плоскость тела. Поворот наружу — только до нейтрали (0°), отведение в сторону — не больше 90°","При задней нестабильности: избегать сочетания сгибания, приведения и поворота внутрь; иммобилизация в нейтральном положении или лёгком отведении (около 10–30°)","Никакой опоры весом тела на руку и осевой нагрузки","Правило «держи кисть в поле зрения»: первые ~3 недели рука не выходит за линию взгляда — так сустав остаётся в безопасном среднем диапазоне","Косыночную повязку носить по назначенному режиму"]',
    '["Срок иммобилизации завершён по плану (молодым и при высоком риске — до 3 недель; старше 40 лет достаточно 1 недели)","Поворот руки наружу с локтем у тела достигает нейтрали (0°) безболезненно","Боль покоя и ночная боль стихли — спите без пробуждений от боли","Нет онемения и слабости в руке, чувствительность над плечом сохранна","Косыночная повязка снята по плану"]',
    'dumbbell', '#10B981', '#EDFAF5',
    'Защитить сустав, унять боль, держать руку в безопасном диапазоне',
    '["Иммобилизация в косыночной повязке","Свободные активные движения локтя, запястья и кисти","Маятниковые покачивания руки","Лёгкие напряжения мышц без движения (вращательная манжета, дельтовидная, бицепс) с рукой у тела, в безболезненном диапазоне","Раннее включение мышц вокруг лопатки при отсутствии боли","Лёгкое сгибание и поворот наружу с помощью, в безопасных пределах по переносимости"]',
    '["Умеренная боль покоя и при движении соседних суставов допустима, если она постепенно стихает","Тревожно: нарастающая боль, ночная боль, не дающая спать, резкая боль при попытке движения — сигнал перегрузки или осложнения"]',
    '["Несколько коротких занятий в день","Косыночная повязка — по режиму, снимать только на разрешённое","Прикладывайте холод при отёке через ткань, не на голую кожу","Двигайте локтем, запястьем и кистью свободно — их ограничивать не нужно"]',
    '["Онемение или слабость в руке, потеря чувствительности над плечом — возможное повреждение нерва, к врачу","Похолодание, бледность, отсутствие пульса в руке — сосудистая проблема, срочно к врачу","Ощущение повторного «выскакивания» плеча или повторный вывих — к врачу","Неутихающая или нарастающая боль, повышение температуры — к врачу"]',
    '[{"q":"Почему нельзя сразу двигать рукой самому?","a":"После вывиха капсуле и связкам нужно прирасти на месте. Активные движения и провокационные положения тянут заживающую ткань и повышают риск повторного вывиха. Поэтому пока рука работает мягко и в безопасном диапазоне."},{"q":"Что такое «положение опасения»?","a":"Это сочетание отведения руки в сторону и поворота наружу — именно в нём плечо вывихивается чаще всего при передней нестабильности. В первые недели его строго избегаем."},{"q":"Зачем держать кисть в поле зрения?","a":"Простое правило: если рука не выходит за линию взгляда, сустав остаётся в среднем безопасном диапазоне и не попадает в опасные положения."}]'
),
