-- =====================================================
-- 2. Структурированные критерии перехода shoulder_instability_conservative
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
--    Фазы 1–4 (терминальная Ф4 несёт критерии возврата к спорту).
--    measurement = боль ВАШ (vas_score+pain) ТОЛЬКО; в этом протоколе порогов по боли нет
--    (боль описана качественно) → measurement-критериев вовсе нет; объём/сила/срок → instructor_check.
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 1 → Фаза 2 (защита и заживление → восстановление движений)
  (1, 'immobilization_done_p1',  'Срок иммобилизации завершён по плану (молодым/высокий риск — до 3 недель; старше 40 лет — достаточно 1 недели)', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 14::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (1, 'passive_er_neutral_p1',   'Пассивный поворот руки наружу (локоть у тела) достигает нейтрали (0°) безболезненно',         'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (1, 'sleep_no_pain_p1',        'Боль покоя и ночная боль стихли — сон без пробуждений от боли',                              'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Стихли ли боль покоя и ночная боль настолько, что вы спите без пробуждений от боли?', 'Сравните, как вы спите сейчас и в первые дни после вывиха', 30::smallint, TRUE),
  (1, 'no_neuro_deficit_p1',     'Нет онемения и слабости в руке, чувствительность над плечом сохранна (оценка куратора)',      'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (1, 'sling_removed_p1',        'Косыночная повязка снята / режим иммобилизации завершён по плану',                           'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, FALSE),

  -- Фаза 2 → Фаза 3 (восстановление движений → укрепление и контроль)
  (2, 'active_elevation_140_p2', 'Активный подъём руки вперёд не менее 140–150°',                                              'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'er_safe_45_p2',           'Поворот руки наружу в безопасном диапазоне (локоть у тела) не менее 45°',                     'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (2, 'rc_strength_mmt4_p2',     'Сила вращательной манжеты по мануальному тесту не менее 4 из 5',                              'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (2, 'adl_below_shoulder_p2',   'Бытовые движения ниже уровня плеча даются без боли',                                         'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Получается выполнять бытовые движения ниже уровня плеча без боли?', 'Например: одеться, поесть, взять предмет с полки на уровне пояса', 40::smallint, TRUE),
  (2, 'scapular_rhythm_ok_p2',   'Плечо и лопатка работают слаженно, нет болезненной дуги при активном подъёме (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, FALSE),

  -- Фаза 3 → Фаза 4 (укрепление и контроль → возврат к активности и спорту)
  (3, 'full_painfree_rom_p3',    'Полный безболезненный объём движений (подъём руки около 180°, повороты симметричны здоровой стороне)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (3, 'rotator_strength_80_p3',  'Сила вращателей не менее 80% от здоровой стороны',                                            'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 20::smallint, TRUE),
  (3, 'stable_overhead_p3',      'Плечо ощущается стабильным при движениях над головой',                                       'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Чувствуете ли вы плечо стабильным при движениях над головой?', 'Оцените по подъёму и работе руки выше уровня плеча', 30::smallint, TRUE),
  (3, 'apprehension_neg_p3',     'Нет чувства опасения при отведении и повороте руки наружу (тест опасения отрицательный)',     'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (3, 'control_tasks_ok_p3',     'Задания на чувство положения руки и лёгкие прыжково-бросковые упражнения выполняются под контролем без признаков нестабильности', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, FALSE),

  -- Фаза 4 (терминальная) — критерии возврата к спорту/работе
  (4, 'strength_90_rts_p4',      'Для возврата к спорту/работе: сила не менее 90% от здоровой стороны (симметрия)',             'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 10::smallint, TRUE),
  (4, 'full_symmetric_rom_p4',   'Полный симметричный объём движений',                                                         'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (4, 'psych_ready_p4',          'Психологическая готовность вернуться к спорту без страха повторного вывиха',                  'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Психологически ли вы готовы вернуться к спорту без страха повторного вывиха?', 'Можно ориентироваться на специальный опросник готовности (SIRSI), который предложит куратор', 30::smallint, TRUE),
  (4, 'apprehension_reloc_neg_p4','Тест опасения и тест возврата в исходное положение отрицательны (оценка куратора)',           'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (4, 'sport_tests_passed_p4',   'Спорт-специфичные функциональные тесты выполняются успешно (например, тесты с опорой на руки и на устойчивость верхней части тела)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 50::smallint, FALSE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'shoulder_instability_conservative' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
